@charset "UTF-8";
@import url("https://fonts.googleapis.com/css2?family=Poppins:wght@400;500;600;700&display=swap");
:root {
  --font-primary: "Poppins", sans-serif;
  --color-text-dark: #2D3748;
  --color-text-gray: #718096;
  --color-text-light: #A0AEC0;
  --color-bg: #ffffff;
  --color-bg-app: #F7FAFC; /* Gris très léger pour le fond */
  --color-border: #E2E8F0;
  --color-primary: #82DB34;
  --color-primary-hover: #75C62F;
  --color-secondary: #EDF2F7;
  --color-secondary-hover: #E2E8F0;
  --color-success-bg: #F0FFF4;
  --color-success-text: #38A169;
  --radius-main: 16px;
  --radius-sm: 8px;
  --radius-pill: 50px;
  --shadow-sm: 0 1px 3px rgba(0,0,0,0.05);
  --shadow-card: 0 10px 25px -5px rgba(0, 0, 0, 0.05);
}

body, html {
  margin: 0;
  padding: 0;
  height: auto;
  background-color: transparent;
  font-family: var(--font-primary);
  color: var(--color-text-dark);
}

.checkout-page {
  width: 100%;
  max-width: 600px;
  margin: 0 auto;
  padding: 20px 10px;
  box-sizing: border-box;
  display: flex;
  flex-direction: column;
  gap: 32px;
}

/*======================================
  1. En-tête (Succès)
======================================*/
.header-success {
  text-align: center;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 12px;
}

.icon-success-circle {
  width: 64px;
  height: 64px;
  background-color: var(--color-success-bg);
  color: var(--color-success-text);
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  box-shadow: 0 0 0 6px rgba(240, 255, 244, 0.5);
}

.header-success h1 {
  font-size: 1.6rem;
  font-weight: 700;
  margin: 0;
  color: var(--color-text-dark);
}

.header-success p {
  font-size: 0.95rem;
  color: var(--color-text-gray);
  margin: 0;
  line-height: 1.5;
}

/*======================================
  2. Zone Contrat (Checkout)
======================================*/
.section-title {
  font-size: 1.1rem;
  font-weight: 700;
  margin: 0 0 12px 0;
  color: var(--color-text-dark);
}

.contract-card {
  background: var(--color-bg);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-main);
  box-shadow: var(--shadow-sm);
  padding: 20px;
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.contract-main {
  display: flex;
  align-items: center;
  gap: 16px;
}

.contract-logo {
  width: 60px;
  height: 60px;
  border: 1px solid var(--color-border);
  border-radius: var(--radius-sm);
  padding: 8px;
  display: flex;
  align-items: center;
  justify-content: center;
  background-color: var(--color-bg);
}

.contract-logo img {
  max-width: 100%;
  max-height: 100%;
  object-fit: contain;
}

.contract-info {
  flex: 1;
}

.contract-insurer {
  font-size: 1.1rem;
  font-weight: 700;
  margin: 0;
}

.contract-offer {
  font-size: 0.9rem;
  font-weight: 500;
  color: var(--color-text-gray);
  margin-top: 2px;
}

.contract-price-box {
  text-align: right;
  border-left: 1px solid var(--color-border);
  padding-left: 16px;
}

.contract-price {
  font-size: 1.6rem;
  font-weight: 700;
  letter-spacing: -0.02em;
  color: var(--color-text-dark);
}

.contract-unit {
  font-size: 0.85rem;
  font-weight: 500;
  color: var(--color-text-gray);
}

.contract-footer {
  border-top: 1px dashed var(--color-border);
  padding-top: 16px;
  display: flex;
  justify-content: space-between;
  align-items: center;
  font-size: 0.9rem;
}

.effective-date {
  color: var(--color-text-dark);
  font-weight: 500;
}

.effective-date span {
  color: var(--color-success-text);
  font-weight: 600;
  background: var(--color-success-bg);
  padding: 2px 8px;
  border-radius: 4px;
  margin-left: 6px;
}

/* Bouton Télécharger */
.btn-download {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 8px 16px;
  background-color: var(--color-secondary);
  color: var(--color-text-dark);
  font-family: var(--font-primary);
  font-size: 0.85rem;
  font-weight: 600;
  border: none;
  border-radius: var(--radius-sm);
  cursor: pointer;
  transition: background 0.2s;
  text-decoration: none;
}

.btn-download:hover {
  background-color: var(--color-secondary-hover);
}

/*======================================
  3. Zone Démarches
======================================*/
.steps-card {
  background: var(--color-bg);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-main);
  box-shadow: var(--shadow-sm);
  padding: 24px;
}

.step-list {
  display: flex;
  flex-direction: column;
  gap: 20px;
}

.step-item {
  display: flex;
  align-items: center;
  gap: 16px;
}

.step-number {
  width: 32px;
  height: 32px;
  background-color: var(--color-bg-app);
  border: 1px solid var(--color-border);
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: 600;
  color: var(--color-text-gray);
  font-size: 0.9rem;
  flex-shrink: 0;
}

.step-text {
  font-size: 0.95rem;
  font-weight: 500;
  color: var(--color-text-dark);
}

/*======================================
  4. CTA Final
======================================*/
.btn-cta-final {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 12px;
  padding: 16px 24px;
  background-color: var(--color-primary);
  color: white;
  font-family: var(--font-primary);
  font-size: 1.1rem;
  font-weight: 600;
  border: none;
  border-radius: var(--radius-pill);
  cursor: pointer;
  width: 100%;
  box-shadow: 0 4px 12px rgba(130, 219, 52, 0.2);
  transition: all 0.2s;
  text-decoration: none;
}

.btn-cta-final:hover {
  background-color: var(--color-primary-hover);
  transform: translateY(-2px);
  box-shadow: 0 6px 16px rgba(130, 219, 52, 0.3);
}

@media screen and (max-width: 480px) {
  .contract-main {
    flex-direction: column;
    text-align: center;
    gap: 12px;
  }
  .contract-price-box {
    border-left: none;
    border-top: 1px solid var(--color-border);
    padding-left: 0;
    padding-top: 12px;
    width: 100%;
    text-align: center;
  }
  .contract-footer {
    flex-direction: column;
    gap: 16px;
  }
}

