		<path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"></path>
		<polyline points="7 10 12 15 17 10"></polyline>
		<line x1="12" y1="15" x2="12" y2="3"></line>
	</svg>
);

const IconArrowRight = () => (
	<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
		<line x1="5" y1="12" x2="19" y2="12"></line>
		<polyline points="12 5 19 12 12 19"></polyline>
	</svg>
);

function ConfirmationCheckout() {
	// Extraction blindée de l'offre
	let rawData = appsmith.model.offer || appsmith.model || {};
	let offer = rawData;

	if (typeof rawData === 'string') {
		try { offer = JSON.parse(rawData); } catch (e) { }
	}
	if (offer.offer) offer = offer.offer; // Désimbrication si nécessaire

	// Calcul de la date (Aujourd'hui + 31 jours)
	const today = new Date();
	const effectiveDate = new Date(today.setDate(today.getDate() + 31));
	const formattedDate = effectiveDate.toLocaleDateString('fr-FR', { 
		day: 'numeric', 
		month: 'long', 
		year: 'numeric' 
	});

	// Variables sécurisées
	const partner = offer.partner || {};
	const partnerName = partner.name || "Assureur";
	const partnerLogo = partner.logo || "";
	const partnerColor = partner.color || "var(--color-border)";

	const offerName = offer.name || "Formule non précisée";
	const rawPrice = offer.impacted_price || offer.price || "0";
	const formattedPrice = String(rawPrice).replace('.', ',');
	const docUrl = offer.information_paper || "#";

	const partnerInitial = partnerName.charAt(0).toUpperCase();

	// --- LA MODIFICATION EST ICI ---
	// Redirection gérée par Appsmith pour utiliser l'URL dynamique
	const handleRedirect = () => {
		appsmith.triggerEvent("onFinalizeClick");
	};

	return (
		<div className="checkout-page">

			{/* 1. En-tête */}
			<div className="header-success">
				<div className="icon-success-circle">
					<IconCheckCircle />
				</div>
				<h1>C'est validé ! 🎉</h1>
				<p>Le nouveau contrat d'assurance est en cours d'édition, voici le récapitulatif de votre futur contrat</p>
			</div>

			{/* 2. Zone Contrat */}
			<div>
				<h2 className="section-title">Votre nouveau contrat</h2>
				<div className="contract-card" style={{ borderTop: `4px solid ${partnerColor}` }}>
					<div className="contract-main">

						{/* C'EST ICI QUE LE LOGO EST AFFICHÉ */}
						<div className="contract-logo" style={{ backgroundColor: partnerLogo ? "var(--color-bg)" : partnerColor }}>
							{partnerLogo ? (
								<img 
									src={partnerLogo} 
									alt={`Logo ${partnerName}`} 
									style={{ width: '100%', height: '100%', objectFit: 'contain', padding: '4px', boxSizing: 'border-box' }}
								/>
							) : (
								<div className="logo-fallback">{partnerInitial}</div>
							)}
						</div>

						<div className="contract-info">
							<p className="contract-insurer">{partnerName}</p>
							<p className="contract-offer">{offerName}</p>
						</div>
						<div className="contract-price-box">
							{offer.is_estimation === true || offer.is_estimation === "true" ? (
								<div className="contract-price" style={{fontSize: "1.2rem"}}>Sur devis</div>
							) : (
								<>
									<div className="contract-price">{formattedPrice}€</div>
									<div className="contract-unit">/mois</div>
								</>
							)}
						</div>
					</div>

					<div className="contract-footer">
						<div className="effective-date">
							Prise d'effet estimée : <span>Le {formattedDate}</span>
						</div>
						{docUrl !== "#" && (
							<a href={docUrl} target="_blank" rel="noopener noreferrer" className="btn-download">
								<IconDownload /> Fiche info.
							</a>
						)}
					</div>
				</div>
			</div>

			{/* 3. Zone Démarches */}
			<div>
				<h2 className="section-title">Dernières démarches à suivre</h2>
				<div className="steps-card">
					<div className="step-list">
						<div className="step-item">
							<div className="step-number">1</div>
							<div className="step-text">Renseigner le mandat de prélèvement (RIB)</div>
						</div>
						<div className="step-item">
							<div className="step-number">2</div>
							<div className="step-text">Déposer vos pièces justificatives demandées</div>
						</div>
						<div className="step-item">
							<div className="step-number">3</div>
							<div className="step-text">Signer la demande de résiliation de votre ancien contrat</div>
						</div>
					</div>
				</div>
			</div>

			{/* 4. Bouton Final */}
			<button className="btn-cta-final" onClick={handleRedirect}>
				Finaliser la démarche sur Ideel <IconArrowRight />
			</button>

		</div>
	);
}

function renderApp() {
	ReactDOM.render(<ConfirmationCheckout />, document.getElementById("root"));
}

appsmith.onReady(() => renderApp());
appsmith.onModelChange(() => renderApp());
